-- Week 1 / Game 1 sheet-derived score load.
-- Run after supabase/game_score_storage.sql.

VALUES (32, 1, 1, 'sheet_import', 'complete', NOW(), '{"sourceFile":"XXXII Game1.xlsx","startDate":"2026-03-30","endDate":"2026-04-05"}'::jsonb);

ON CONFLICT (season_number, game_number, matchup_key) DO UPDATE SET
  week_number = EXCLUDED.week_number, league_code = EXCLUDED.league_code, away_score = EXCLUDED.away_score, home_score = EXCLUDED.home_score, away_psr = EXCLUDED.away_psr, home_psr = EXCLUDED.home_psr, away_lead = EXCLUDED.away_lead, home_lead = EXCLUDED.home_lead, payload = EXCLUDED.payload, calculated_at = NOW();

ON CONFLICT (season_number, game_number, matchup_key, team_name, stat_date) DO UPDATE SET
  week_number = EXCLUDED.week_number, home_away = EXCLUDED.home_away, sheet_points = EXCLUDED.sheet_points, calculated_points = EXCLUDED.calculated_points, offense_points = EXCLUDED.offense_points, pitching_points = EXCLUDED.pitching_points, payload = EXCLUDED.payload, calculated_at = NOW();

ON CONFLICT (season_number, game_number, matchup_key, team_name, player_name, roster_slot, stat_date) DO UPDATE SET
  week_number = EXCLUDED.week_number, roster_slot = EXCLUDED.roster_slot, sheet_points = EXCLUDED.sheet_points, calculated_points = EXCLUDED.calculated_points, scoring_breakdown = EXCLUDED.scoring_breakdown, raw_stats = EXCLUDED.raw_stats, calculated_at = NOW();
